const d = $input.first().json.body;

const esc = (v) => String(v ?? '').replaceAll('&','&amp;').replaceAll('<','&lt;').replaceAll('>','&gt;').replaceAll('"','&quot;').replaceAll("'",'&#39;');
const br  = (v) => esc(v).replace(/\n/g,'<br/>');
const euro = (v) => new Intl.NumberFormat('nl-NL',{style:'currency',currency:'EUR'}).format(Number(v??0));
const dateFmt = (v) => { try{ return new Intl.DateTimeFormat('nl-NL',{dateStyle:'long'}).format(new Date(v)); }catch(e){return String(v??'');} };

// -- Aanpassen naar wens --
const rekeninghouder = 'Stijn van de Pol';
// -------------------------

const fromName  = esc(d.from?.companyName ?? '');
const fromEmail = esc(d.from?.email ?? '');
const fromWeb   = esc(d.from?.websiteUrl ?? '');
const fromAddr  = br(d.from?.address ?? '');
const fromVat   = esc(d.from?.vatNumber ?? '');
const fromKvk   = esc(d.from?.kvkNumber ?? '');
const fromIban  = esc(d.from?.iban ?? '');
const fromBank  = esc(d.from?.bankName ?? '');
const fromPhone = esc(d.from?.phone ?? '');

const factuurNr   = esc(d.invoiceNumber ?? 'ONBEKEND');
const vatRate     = Number(d.vatRate ?? 21);
const subtotal    = Number(d.subtotal ?? 0);
const vatAmount   = Number(d.vatAmount ?? subtotal * vatRate / 100);
const totalAmount = Number(d.totalAmount ?? subtotal + vatAmount);

const clientName    = esc(d.client?.companyName ?? '');
const clientContact = esc(d.client?.contactName ?? '');
const clientAddr    = br(d.client?.address ?? '');
const clientEmail   = esc(d.client?.email ?? '');

const lineRows = Array.isArray(d.lineItems) && d.lineItems.length > 0
  ? d.lineItems.map(item => `<tr>
      <td>${esc(item.description ?? '')}${item.note ? `<div class="note">${esc(item.note)}</div>` : ''}</td>
      <td class="r">${item.quantity != null ? esc(String(item.quantity)) + (item.unit ? '&nbsp;' + esc(item.unit) : '') : ''}</td>
      <td class="r">${item.unitPrice != null ? euro(item.unitPrice) : ''}</td>
      <td class="r">${euro(item.amount ?? item.subtotal ?? 0)}</td>
    </tr>`).join('')
  : `<tr>
      <td>${esc(d.description ?? '')}${d.project ? `<div class="note">${esc(d.project.name ?? d.project)}</div>` : ''}</td>
      <td class="r">${d.quantity != null ? esc(String(d.quantity)) + (d.unit ? '&nbsp;' + esc(d.unit) : '') : ''}</td>
      <td class="r">${d.unitPrice != null ? euro(d.unitPrice) : ''}</td>
      <td class="r">${euro(subtotal)}</td>
    </tr>`;

const html = `<!DOCTYPE html>
<html lang="nl">
<head>
<meta charset="UTF-8"/>
<style>
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
body {
  font-family: Arial, sans-serif;
  font-size: 10.5px;
  line-height: 1.5;
  color: #1a1a1a;
  background: #fff;
  padding: 44px 52px;
}
.header {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  margin-bottom: 48px;
}
.brand { font-size: 18px; font-weight: 700; color: #111; letter-spacing: -.2px; }
.brand-sub { font-size: 9.5px; color: #777; margin-top: 3px; }
.header-info {
  display: grid;
  grid-template-columns: auto auto;
  gap: 3px 20px;
  font-size: 10px;
  text-align: left;
}
.hi-lbl { font-weight: 700; color: #111; white-space: nowrap; }
.hi-val { color: #444; }
.recipient {
  margin-bottom: 36px;
  font-size: 10.5px;
  line-height: 1.75;
  color: #1a1a1a;
}
.recipient strong { font-weight: 700; }
.recipient .tav { color: #777; font-size: 10px; }
.doc-title {
  font-size: 17px;
  font-weight: 700;
  letter-spacing: .5px;
  color: #111;
  margin-bottom: 14px;
}
.meta {
  display: grid;
  grid-template-columns: auto 1fr;
  gap: 4px 16px;
  font-size: 10.5px;
  max-width: 340px;
}
.mk { font-weight: 700; color: #111; }
.mv { color: #333; }
.divider { border: none; border-top: 1px solid #d0d0d0; margin: 18px 0 0 0; }
.items { width: 100%; border-collapse: collapse; margin-top: 0; }
.items thead tr {
  border-top: 1.5px solid #111;
  border-bottom: 1.5px solid #111;
}
.items th {
  font-size: 9px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: .04em;
  color: #555;
  padding: 7px 8px;
  text-align: left;
}
.items th.r { text-align: right; }
.items tbody td {
  padding: 9px 8px;
  font-size: 10.5px;
  vertical-align: top;
  border-bottom: 1px solid #ececec;
  color: #1a1a1a;
}
.items tbody td.r {
  text-align: right;
  font-variant-numeric: tabular-nums;
  white-space: nowrap;
}
.note { font-size: 9.5px; color: #888; margin-top: 2px; }
.bottom {
  display: flex;
  justify-content: space-between;
  align-items: flex-end;
  margin-top: 2px;
  padding-bottom: 20px;
  border-bottom: 1px solid #ddd;
}
.vat-tbl { border-collapse: collapse; font-size: 9.5px; margin-top: 14px; }
.vat-tbl th {
  font-weight: 700;
  color: #555;
  text-align: left;
  padding: 5px 24px 4px 0;
  border-bottom: 1px solid #ccc;
}
.vat-tbl td { padding: 5px 24px 0 0; color: #444; }
.totals { border-collapse: collapse; min-width: 200px; font-size: 10.5px; }
.totals td { padding: 4px 0 4px 24px; color: #555; }
.totals td:last-child {
  text-align: right;
  font-variant-numeric: tabular-nums;
  white-space: nowrap;
}
.totals .grand td {
  font-size: 12px;
  font-weight: 700;
  color: #111;
  border-top: 1.5px solid #111;
  padding-top: 8px;
}
.payment {
  padding-top: 18px;
  font-size: 10.5px;
  color: #333;
  line-height: 1.9;
}
.footer {
  display: flex;
  justify-content: space-between;
  margin-top: 40px;
  padding-top: 10px;
  border-top: 1px solid #e5e5e5;
  font-size: 9px;
  color: #bbb;
}
</style>
</head>
<body>

<div class="header">
  <div>
    <div class="brand">${fromName}</div>
    ${fromWeb || fromEmail ? `<div class="brand-sub">${fromWeb}${fromWeb && fromEmail ? ' &middot; ' : ''}${fromEmail}</div>` : ''}
  </div>
  <div class="header-info">
    ${fromAddr  ? `<span class="hi-lbl">Adres</span><span class="hi-val">${fromAddr}</span>` : ''}
    ${fromPhone ? `<span class="hi-lbl">Telefoon</span><span class="hi-val">${fromPhone}</span>` : ''}
    ${fromIban  ? `<span class="hi-lbl">IBAN</span><span class="hi-val">${fromIban}${fromBank ? ' &middot; ' + fromBank : ''}</span>` : ''}
    ${fromKvk   ? `<span class="hi-lbl">KVK</span><span class="hi-val">${fromKvk}</span>` : ''}
    ${fromVat   ? `<span class="hi-lbl">BTW</span><span class="hi-val">${fromVat}</span>` : ''}
  </div>
</div>

<div class="recipient">
  <strong>${clientName}</strong><br/>
  ${clientContact ? `<span class="tav">T.a.v. ${clientContact}</span><br/>` : ''}
  ${clientAddr}${clientEmail ? `<br/>${clientEmail}` : ''}
</div>

<div class="doc-title">FACTUUR</div>
<div class="meta">
  <span class="mk">Factuurnummer</span><span class="mv">${factuurNr}</span>
  <span class="mk">Factuurdatum</span><span class="mv">${dateFmt(d.issueDate)}</span>
  <span class="mk">Vervaldatum</span><span class="mv">${dateFmt(d.dueDate)}</span>
</div>
<hr class="divider"/>

<table class="items">
  <thead>
    <tr>
      <th>Omschrijving</th>
      <th class="r">Aantal</th>
      <th class="r">Tarief</th>
      <th class="r">Bedrag excl. BTW</th>
    </tr>
  </thead>
  <tbody>${lineRows}</tbody>
</table>

<div class="bottom">
  <table class="vat-tbl">
    <thead>
      <tr>
        <th>BTW-percentage</th>
        <th>Grondslag</th>
        <th>BTW-bedrag</th>
      </tr>
    </thead>
    <tbody>
      <tr>
        <td>${vatRate === 0 ? 'Vrijgesteld' : vatRate + '%'}</td>
        <td>${euro(subtotal)}</td>
        <td>${euro(vatAmount)}</td>
      </tr>
    </tbody>
  </table>
  <table class="totals">
    <tr><td>Subtotaal</td><td>${euro(subtotal)}</td></tr>
    <tr><td>BTW ${vatRate}%</td><td>${euro(vatAmount)}</td></tr>
    <tr class="grand"><td>Totaal te voldoen</td><td>${euro(totalAmount)}</td></tr>
  </table>
</div>

<div class="payment">
  ${fromIban ? `Betaal het bedrag voor de vervaldatum op <strong>${fromIban}</strong> t.n.v. <strong>${rekeninghouder}</strong> o.v.v. factuurnummer <strong>${factuurNr}</strong>.` : ''}
  ${d.notes ? `<br/><br/>${br(d.notes)}` : ''}
  ${fromEmail ? `<br/><br/>Vragen? Neem contact op via <strong>${fromEmail}</strong>.` : ''}
</div>

<div class="footer">
  <span>${fromName}${fromAddr ? ' &middot; ' + fromAddr.replace(/<br\/>/g, ', ') : ''}</span>
  <span>${fromKvk ? 'KVK: ' + fromKvk : ''}${fromKvk && fromVat ? ' &middot; ' : ''}${fromVat ? 'BTW: ' + fromVat : ''}</span>
</div>

</body>
</html>`;

return [{ json: { ...d, html } }];
